-- ═══════════════════════════════════════════════════════════════════
-- CodeQuest · Migración 021 — Redes y Sistemas · Módulo 2: OSI y TCP/IP
-- ═══════════════════════════════════════════════════════════════════
-- Contenido completo del módulo: 6 lecciones + examen de región.
-- El diagrama comparativo OSI vs TCP/IP usa NetworkDiagram (data-driven):
-- dos columnas de capas alineadas por altura + enlaces de mapeo. Es el
-- diagrama reutilizable que pidió Karen para nube y DFIR.
-- Idempotente: borra y recrea las lecciones de ESTE módulo.
-- Ejecutar DESPUÉS de 006.
-- ═══════════════════════════════════════════════════════════════════

-- Limpia el módulo (cascade borra sus content_blocks)
delete from public.lessons
where module_id = (
  select m.id
  from public.modules m
  join public.courses c on c.id = m.course_id
  where c.slug = 'redes-y-sistemas' and m.slug = 'm02-modelos-osi-tcpip'
);

-- ── Lecciones del módulo ──────────────────────────────────────────────
insert into public.lessons (module_id, slug, title, kind, xp, sort_order)
select m.id, v.slug, v.title, v.kind, v.xp, v.ord
from public.modules m
join public.courses c on c.id = m.course_id,
     (values
       ('m02-l01-por-que-capas',      'Por qué pensar en capas',           'leccion', 20, 1),
       ('m02-l02-osi-capas-1-4',      'OSI: capas 1 a 4',                  'leccion', 20, 2),
       ('m02-l03-osi-capas-5-7',      'OSI: capas 5 a 7',                  'leccion', 20, 3),
       ('m02-l04-tcpip-modelo-real',  'TCP/IP: el modelo real',            'leccion', 20, 4),
       ('m02-l05-osi-vs-tcpip',       'OSI vs TCP/IP: el mapa completo',   'leccion', 20, 5),
       ('m02-l06-encapsulamiento',    'Encapsulamiento: el viaje del dato','leccion', 20, 6),
       ('m02-x01-examen',             'Examen: Los modelos OSI y TCP/IP',  'examen',  40, 7)
     ) as v(slug, title, kind, xp, ord)
where c.slug = 'redes-y-sistemas' and m.slug = 'm02-modelos-osi-tcpip';

-- ═════════════════════════════════════════════════════════════════════
-- L01 · Por qué pensar en capas
-- ═════════════════════════════════════════════════════════════════════
insert into public.content_blocks (lesson_id, sort_order, kind, payload)
select l.id, v.ord, v.kind, v.payload::jsonb
from public.lessons l
join public.modules m on m.id = l.module_id
join public.courses c on c.id = m.course_id,
(values
  (1, 'texto', $j${"title":"El problema: hablar todos los idiomas a la vez","body":"Piensa en todo lo que pasa cuando la clínica envía un resultado de laboratorio a otra sede por mensajería: alguien redacta el informe, otro lo mete en un sobre con la dirección, el mensajero lo recoge, un centro de clasificación decide la ruta y un camión lo lleva. Nadie hace TODO: cada quien domina su trabajo y confía en el siguiente. Ahora imagina programar una app de citas que además tuviera que saber de voltajes del cable, de ondas Wi-Fi y de rutas entre ciudades. Imposible de construir y de mantener. Las redes resuelven esto igual que la mensajería: dividen la comunicación en CAPAS, cada una con un trabajo concreto, que solo habla con la capa de arriba y la de abajo."}$j$),
  (2, 'texto', $j${"title":"Lo que ganas al pensar en capas","body":"Primero, INDEPENDENCIA: si cambias el Wi-Fi por cable, tus apps ni se enteran — solo cambiaste la capa de abajo. Segundo, INTEROPERABILIDAD: equipos de fabricantes distintos se entienden porque cada capa respeta reglas comunes. Tercero, DIAGNÓSTICO: puedes aislar el problema capa por capa — ¿hay señal?, ¿tengo dirección?, ¿responde el servicio? De hecho ya lo hiciste sin saberlo: en el laboratorio del módulo 1, ping al router probaba TU red y ping a 8.8.8.8 probaba la salida a internet. Dos capas de un diagnóstico. Y cuarto, VOCABULARIO: cuando un técnico dice 'es un problema de capa 3', cualquier colega del mundo sabe de qué habla. Ese idioma común es el modelo OSI, y lo aprendes en este módulo."}$j$),
  (3, 'quiz', $j${"variant":"multiple_choice","prompt":"¿Cuál es la idea central del modelo en capas?","options":["Que un solo programa muy completo se encargue de todo","Mantener copias de seguridad de toda la red","Dar a cada capa un trabajo; habla solo con sus vecinas","Que cada fabricante invente sus propias reglas de red"],"correctIndex":2,"feedback":{"correct":"Correcto. Como la mensajería de la clínica: cada quien su trabajo, con interfaces claras entre vecinos.","incorrect":"La clave es dividir y especializar: cada capa hace UN trabajo y solo conversa con la capa de arriba y la de abajo."}}$j$),
  (4, 'quiz', $j${"variant":"multiple_choice","prompt":"Cambias tu laptop del Wi-Fi al cable y tus aplicaciones siguen funcionando sin tocar nada. ¿Qué propiedad de las capas lo explica?","options":["La mayor velocidad que ofrece el cable de red","Fue casualidad que las aplicaciones siguieran funcionando","Que el cable y el Wi-Fi son en realidad lo mismo","La independencia: cambió una capa de abajo, no las de arriba"],"correctIndex":3,"feedback":{"correct":"Exacto. Las apps viven en capas superiores: no les importa si abajo hay ondas o cobre.","incorrect":"Es la independencia entre capas: el medio físico cambió, pero las capas superiores ni se enteraron."}}$j$),
  (5, 'quiz', $j${"variant":"multiple_choice","prompt":"En el lab del módulo 1 hiciste ping al router y luego ping a 8.8.8.8. ¿Por qué ese orden es un diagnóstico 'por capas'?","options":["Primero pruebas tu red local y luego la salida a internet","Porque el router responde mucho más rápido que Google","Porque 8.8.8.8 es más difícil de teclear que un nombre","No lo es: da igual en qué orden hagas los pings"],"correctIndex":0,"feedback":{"correct":"Correcto. Aislar por tramos/capas es EL método de diagnóstico profesional: de lo cercano a lo lejano.","incorrect":"El orden importa: si el router responde, tu tramo local funciona y el problema está más allá. Eso es aislar por capas."}}$j$),
  (6, 'resumen', $j${"title":"Resumen — Por qué pensar en capas","points":["Comunicarse en red implica muchos trabajos a la vez; las capas los reparten: cada una hace uno y habla solo con sus vecinas.","Independencia: cambiar una capa (Wi-Fi → cable) no afecta a las demás.","Interoperabilidad: fabricantes distintos se entienden respetando las reglas de cada capa.","Diagnóstico: los problemas se aíslan capa por capa, de lo cercano a lo lejano.","El modelo OSI es el vocabulario común de la profesión: 'capa 3' significa lo mismo en todo el mundo."]}$j$)
) as v(ord, kind, payload)
where c.slug = 'redes-y-sistemas' and l.slug = 'm02-l01-por-que-capas';

-- ═════════════════════════════════════════════════════════════════════
-- L02 · OSI: capas 1 a 4
-- ═════════════════════════════════════════════════════════════════════
insert into public.content_blocks (lesson_id, sort_order, kind, payload)
select l.id, v.ord, v.kind, v.payload::jsonb
from public.lessons l
join public.modules m on m.id = l.module_id
join public.courses c on c.id = m.course_id,
(values
  (1, 'texto', $j${"title":"Capas 1 y 2: señales y vecinos","body":"La capa 1, FÍSICA, es todo lo que puedes tocar o medir: voltajes en el cobre, pulsos de luz en la fibra, ondas del Wi-Fi. Aquí viven los medios del módulo 1 — su único trabajo es mover BITS de un lado a otro. La capa 2, ENLACE DE DATOS, organiza esos bits en TRAMAS y las entrega DENTRO de tu red local usando direcciones MAC — el identificador que tu tarjeta de red trae grabado de fábrica, como un número de serie. El switch de la clínica vive exactamente aquí: lee la MAC de destino de cada trama y la entrega solo al puerto correcto. Por eso decimos que el switch es un equipo 'de capa 2'."}$j$),
  (2, 'texto', $j${"title":"Capas 3 y 4: entre redes y de programa a programa","body":"La capa 3, RED, cruza la frontera: envuelve los datos en PAQUETES con direcciones IP y elige rutas ENTRE redes distintas. El router es el equipo de capa 3 — y el módulo 3 entero está dedicado a esta capa. La capa 4, TRANSPORTE, resuelve otro problema: en tu laptop corren a la vez el navegador, el correo y la app de citas, y todos comparten la MISMA IP. El transporte lleva los datos de PROGRAMA a PROGRAMA, de extremo a extremo, con dos estilos que verás en el módulo 4: TCP (fiable y ordenado) y UDP (rápido y sin ceremonia). Fíjate en la escalera: bits entre vecinos (1), tramas dentro de la red (2), paquetes entre redes (3), conversaciones entre programas (4)."}$j$),
  (3, 'quiz', $j${"variant":"multiple_choice","prompt":"¿En qué capa trabaja un switch y qué dirección usa para entregar?","options":["Capa 3, con direcciones IP de red","Capa 2, con direcciones MAC","Capa 1, con niveles de voltaje","Capa 4, con números de puerto"],"correctIndex":1,"feedback":{"correct":"Correcto. El switch lee la MAC de cada trama y la entrega al puerto correcto: equipo de capa 2.","incorrect":"El switch vive en la capa 2 (enlace): entrega tramas dentro de la red local usando direcciones MAC."}}$j$),
  (4, 'quiz', $j${"variant":"multiple_choice","prompt":"¿Qué capa permite que un dato salga de tu red y llegue a una red distinta?","options":["Física, aprovechando que el cable es largo","Enlace, usando la dirección MAC del equipo","Red (capa 3), con IP y routers que eligen la ruta","Transporte, apoyándose en el protocolo TCP"],"correctIndex":2,"feedback":{"correct":"Correcto. La capa 3 es la que cruza fronteras: paquetes, IP y routers.","incorrect":"Cruzar ENTRE redes es el trabajo de la capa 3 (red): direcciones IP y routers que eligen la ruta."}}$j$),
  (5, 'quiz', $j${"variant":"multiple_choice","prompt":"Tu laptop tiene UNA sola IP pero el navegador y el correo reciben cada uno sus propios datos sin mezclarse. ¿Qué capa lo hace posible?","options":["La capa física, que mueve las señales","La capa de enlace, que arma las tramas","La capa de red, que asigna la dirección IP","La capa de transporte: de programa a programa"],"correctIndex":3,"feedback":{"correct":"Exacto. El transporte distingue programa de programa aunque compartan IP — los puertos del módulo 4.","incorrect":"Es la capa 4 (transporte): la IP identifica a la máquina; el transporte reparte entre los programas que corren en ella."}}$j$),
  (6, 'resumen', $j${"title":"Resumen — OSI: capas 1 a 4","points":["Capa 1 · Física: mueve BITS por cobre, fibra u ondas — lo tangible.","Capa 2 · Enlace: TRAMAS dentro de la red local, con direcciones MAC. Aquí vive el switch.","Capa 3 · Red: PAQUETES entre redes distintas, con direcciones IP. Aquí vive el router.","Capa 4 · Transporte: de programa a programa (extremo a extremo). TCP fiable, UDP rápido.","La escalera: bits entre vecinos → tramas en tu red → paquetes entre redes → conversaciones entre programas."]}$j$)
) as v(ord, kind, payload)
where c.slug = 'redes-y-sistemas' and l.slug = 'm02-l02-osi-capas-1-4';

-- ═════════════════════════════════════════════════════════════════════
-- L03 · OSI: capas 5 a 7
-- ═════════════════════════════════════════════════════════════════════
insert into public.content_blocks (lesson_id, sort_order, kind, payload)
select l.id, v.ord, v.kind, v.payload::jsonb
from public.lessons l
join public.modules m on m.id = l.module_id
join public.courses c on c.id = m.course_id,
(values
  (1, 'texto', $j${"title":"Sesión, presentación y aplicación","body":"Las tres capas superiores están cada vez más cerca del usuario. La capa 5, SESIÓN, abre, mantiene y cierra diálogos: que tu inicio de sesión en el sistema de citas siga vivo mientras trabajas es un problema de sesión. La capa 6, PRESENTACIÓN, se ocupa de que ambos lados ENTIENDAN los datos: formatos (texto, imágenes) y cifrado. La capa 7, APLICACIÓN, son los protocolos que usan tus programas para pedir cosas: HTTP para páginas web, DNS para resolver nombres, SMTP para correo. Ojo con el clásico malentendido: la capa de aplicación NO es la app. Chrome no es la capa 7 — HTTP, el idioma que Chrome habla, sí lo es."}$j$),
  (2, 'texto', $j${"title":"Qué se usa de verdad","body":"En el día a día casi nadie separa las capas 5, 6 y 7: los protocolos modernos las traen fusionadas. Cuando entras al sistema de citas por HTTPS, un solo protocolo está manteniendo la sesión, cifrando los datos y transportando la conversación de la web — sesión, presentación y aplicación en el mismo paquete de funciones. Por eso el modelo real de internet (TCP/IP, siguiente lección) las agrupa en UNA sola capa de aplicación. ¿Entonces para qué aprender OSI? Porque es el idioma con el que la profesión HABLA de redes: en soporte, en seguridad y en entrevistas se dice 'capa 7' para el nivel de aplicación, 'capa 3' para el de red. OSI es el mapa; ya verás que TCP/IP es el territorio."}$j$),
  (3, 'quiz', $j${"variant":"multiple_choice","prompt":"¿Cuál de estas afirmaciones sobre la capa 7 es correcta?","options":["Son los protocolos que hablan los programas (HTTP, DNS)","La capa 7 es directamente el navegador web","La capa 7 es el sistema operativo completo del equipo","La capa 7 es la pantalla donde se ve la app"],"correctIndex":0,"feedback":{"correct":"Correcto. Chrome es un programa; HTTP es el idioma de capa 7 que ese programa habla.","incorrect":"La capa de aplicación NO es la app: son los protocolos (HTTP, DNS, SMTP) que las apps usan para comunicarse."}}$j$),
  (4, 'quiz', $j${"variant":"multiple_choice","prompt":"Formatos de datos y cifrado son, en el modelo OSI, trabajo de la capa…","options":["5, la capa de sesión","6, la capa de presentación","7, la capa de aplicación","4, la capa de transporte"],"correctIndex":1,"feedback":{"correct":"Correcto. Presentación = que ambos lados entiendan lo mismo: formatos y cifrado.","incorrect":"Es la capa 6, presentación: formatos y cifrado — que los datos se entiendan igual en ambos extremos."}}$j$),
  (5, 'quiz', $j${"variant":"multiple_choice","prompt":"¿Por qué el modelo TCP/IP agrupa las capas 5, 6 y 7 en una sola?","options":["Para ahorrar espacio y papel en los diagramas","Porque esas tres capas ya casi no se usan","Porque los protocolos modernos hacen los tres a la vez","Porque OSI numeró mal esas capas desde el inicio"],"correctIndex":2,"feedback":{"correct":"Exacto. Sesión, presentación y aplicación viajan fusionadas en los protocolos reales; separarlas ya no refleja la práctica.","incorrect":"Los protocolos reales (HTTPS, por ejemplo) mantienen sesión, cifran y conversan a la vez: por eso TCP/IP las trata como una sola capa."}}$j$),
  (6, 'resumen', $j${"title":"Resumen — OSI: capas 5 a 7","points":["Capa 5 · Sesión: abre, mantiene y cierra diálogos (tu login que sigue vivo).","Capa 6 · Presentación: formatos y cifrado — que ambos lados entiendan los datos.","Capa 7 · Aplicación: los protocolos de los programas (HTTP, DNS, SMTP). La app NO es la capa 7: habla capa 7.","En la práctica, 5-6-7 van fusionadas en los protocolos modernos; TCP/IP las agrupa en una sola capa.","OSI sigue siendo el vocabulario de la profesión: 'capa 7' y 'capa 3' se dicen así en todo el mundo."]}$j$)
) as v(ord, kind, payload)
where c.slug = 'redes-y-sistemas' and l.slug = 'm02-l03-osi-capas-5-7';

-- ═════════════════════════════════════════════════════════════════════
-- L04 · TCP/IP: el modelo real
-- ═════════════════════════════════════════════════════════════════════
insert into public.content_blocks (lesson_id, sort_order, kind, payload)
select l.id, v.ord, v.kind, v.payload::jsonb
from public.lessons l
join public.modules m on m.id = l.module_id
join public.courses c on c.id = m.course_id,
(values
  (1, 'texto', $j${"title":"El modelo con el que se construyó internet","body":"TCP/IP tiene solo 4 capas: ACCESO A RED, INTERNET, TRANSPORTE y APLICACIÓN. No nació en un comité: nació en los laboratorios que construyeron ARPANET, la red que se convirtió en internet — primero funcionó, después se documentó. El modelo OSI llegó años más tarde como estándar teórico de la ISO, elegante y completo… pero internet ya corría sobre TCP/IP y nunca migró. El resultado es la convivencia que ves hoy: TCP/IP ganó en los cables (es lo que de verdad ejecutan las máquinas) y OSI ganó en las aulas y el vocabulario (es como los humanos hablamos de redes)."}$j$),
  (2, 'texto', $j${"title":"El mapeo entre los dos modelos","body":"Las equivalencias son directas. APLICACIÓN de TCP/IP = capas 5+6+7 de OSI (sesión, presentación y aplicación fusionadas, como viste). TRANSPORTE = capa 4, con el mismo nombre en ambos modelos: TCP y UDP. INTERNET = capa 3 de OSI (algunos la llaman también 'capa de red'): IP y routers. ACCESO A RED = capas 1+2: cables, ondas, MAC y switches. Consejo profesional: aunque el mundo corre sobre TCP/IP, cuando alguien numera una capa — 'problema de capa 3', 'firewall de capa 7' — SIEMPRE está usando la numeración OSI. Los dos modelos se usan a la vez: uno para ejecutar, otro para conversar."}$j$),
  (3, 'quiz', $j${"variant":"multiple_choice","prompt":"¿Cuántas capas tiene el modelo TCP/IP y cuál es su origen?","options":["7 capas, diseñadas en teoría por la ISO","5 capas, definidas por los fabricantes de routers","4 capas, inventadas después de OSI para simplificarlo","4 capas, nacidas de la implementación real de internet"],"correctIndex":3,"feedback":{"correct":"Correcto. 4 capas: primero funcionó (ARPANET), después se documentó. OSI llegó más tarde como teoría.","incorrect":"Son 4 capas y vienen de la práctica: ARPANET ya corría sobre TCP/IP antes de que OSI existiera como estándar."}}$j$),
  (4, 'quiz', $j${"variant":"multiple_choice","prompt":"Las capas física y de enlace de OSI corresponden en TCP/IP a…","options":["La capa de acceso a red (cables, ondas, MAC)","La capa internet, que rutea entre redes","La capa de transporte, extremo a extremo","No tienen ningún equivalente en TCP/IP"],"correctIndex":0,"feedback":{"correct":"Correcto. Acceso a red = capas 1+2: cables, ondas, MAC y switches.","incorrect":"Física + enlace se funden en la capa de ACCESO A RED de TCP/IP: todo lo que conecta con tu red local."}}$j$),
  (5, 'quiz', $j${"variant":"multiple_choice","prompt":"Un colega dice 'ese firewall trabaja en capa 7'. ¿Qué numeración está usando y por qué?","options":["TCP/IP, porque es el modelo que se ejecuta","OSI: la profesión numera las capas con OSI","La numeración propia del fabricante del firewall","Ninguna: la capa 7 en realidad no existe"],"correctIndex":1,"feedback":{"correct":"Exacto. TCP/IP para ejecutar, OSI para conversar: 'capa 7' = nivel de aplicación en numeración OSI.","incorrect":"Cuando se numera una capa se usa OSI. TCP/IP ni siquiera tiene 7 capas — por eso 'capa 7' solo tiene sentido en OSI."}}$j$),
  (6, 'resumen', $j${"title":"Resumen — TCP/IP: el modelo real","points":["TCP/IP: 4 capas — acceso a red, internet, transporte y aplicación.","Nació de la práctica (ARPANET); OSI llegó después como estándar teórico.","TCP/IP ganó en los cables; OSI ganó en el vocabulario. Se usan a la vez.","Mapeo: aplicación = OSI 5+6+7 · transporte = 4 · internet = 3 · acceso a red = 1+2.","Cuando alguien numera una capa ('capa 3', 'capa 7') está hablando en OSI."]}$j$)
) as v(ord, kind, payload)
where c.slug = 'redes-y-sistemas' and l.slug = 'm02-l04-tcpip-modelo-real';

-- ═════════════════════════════════════════════════════════════════════
-- L05 · OSI vs TCP/IP: el mapa completo (diagrama comparativo)
-- ═════════════════════════════════════════════════════════════════════
insert into public.content_blocks (lesson_id, sort_order, kind, payload)
select l.id, v.ord, v.kind, v.payload::jsonb
from public.lessons l
join public.modules m on m.id = l.module_id
join public.courses c on c.id = m.course_id,
(values
  (1, 'texto', $j${"title":"Los dos mapas, lado a lado","body":"Hora de ver el módulo entero en una sola imagen. A la izquierda, las 7 capas de OSI; a la derecha, las 4 de TCP/IP. Las ALTURAS cuentan la historia: la capa de aplicación de TCP/IP es alta porque absorbe tres capas de OSI, y la de acceso a red absorbe dos. Toca cada capa para repasar qué hace, y las líneas punteadas para ver cómo se corresponden. Este diagrama te va a acompañar: cuando llegues a los cursos de nube y de análisis forense, volverás a él para ubicar en qué capa ocurre cada cosa."}$j$),
  (2, 'diagrama', $j${"title":"OSI vs TCP/IP","component":"NetworkDiagram","props":{"label":"OSI (el mapa) vs TCP/IP (el territorio)","ancho":520,"alto":412,"grupos":[{"id":"osi","x":16,"y":40,"w":218,"h":356,"titulo":"OSI · 7 capas","descripcion":"El modelo teórico de la ISO: 7 capas. Es el vocabulario de la profesión — cuando alguien numera una capa, usa esta columna."},{"id":"tcpip","x":286,"y":40,"w":218,"h":356,"titulo":"TCP/IP · 4 capas","descripcion":"El modelo real de internet: 4 capas nacidas de la práctica. Es lo que las máquinas ejecutan de verdad."}],"nodos":[{"id":"osi7","x":30,"y":56,"w":190,"h":40,"titulo":"7 · Aplicación","subtitulo":"HTTP, DNS, SMTP","descripcion":"Los protocolos que hablan los programas: HTTP (web), DNS (nombres), SMTP (correo). La app no ES la capa 7: habla capa 7."},{"id":"osi6","x":30,"y":104,"w":190,"h":40,"titulo":"6 · Presentación","subtitulo":"formatos, cifrado","descripcion":"Que ambos lados entiendan los datos: formatos (texto, imágenes) y cifrado."},{"id":"osi5","x":30,"y":152,"w":190,"h":40,"titulo":"5 · Sesión","subtitulo":"diálogos","descripcion":"Abre, mantiene y cierra diálogos: tu inicio de sesión que sigue vivo mientras trabajas."},{"id":"osi4","x":30,"y":200,"w":190,"h":40,"titulo":"4 · Transporte","subtitulo":"TCP, UDP","descripcion":"De programa a programa, extremo a extremo. TCP fiable y ordenado; UDP rápido y sin ceremonia."},{"id":"osi3","x":30,"y":248,"w":190,"h":40,"titulo":"3 · Red","subtitulo":"IP, routers","descripcion":"Paquetes con direcciones IP cruzando ENTRE redes. Aquí vive el router. El módulo 3 es esta capa."},{"id":"osi2","x":30,"y":296,"w":190,"h":40,"titulo":"2 · Enlace","subtitulo":"MAC, switches","descripcion":"Tramas DENTRO de tu red local, entregadas por dirección MAC. Aquí vive el switch."},{"id":"osi1","x":30,"y":344,"w":190,"h":40,"titulo":"1 · Física","subtitulo":"cables, ondas","descripcion":"Bits como señales: voltajes en cobre, luz en fibra, ondas en Wi-Fi. Todo lo tangible del módulo 1."},{"id":"app","x":300,"y":56,"w":190,"h":136,"titulo":"Aplicación","subtitulo":"HTTP, DNS, TLS…","descripcion":"Absorbe las capas 5, 6 y 7 de OSI: los protocolos modernos mantienen sesión, cifran y conversan a la vez."},{"id":"transporte","x":300,"y":200,"w":190,"h":40,"titulo":"Transporte","subtitulo":"TCP, UDP","descripcion":"La capa que conserva nombre y número de trabajo en ambos modelos: TCP y UDP, de programa a programa."},{"id":"internet","x":300,"y":248,"w":190,"h":40,"titulo":"Internet","subtitulo":"IP","descripcion":"La capa 3 de OSI con el nombre del modelo real: IP y routers eligiendo rutas entre redes."},{"id":"acceso","x":300,"y":296,"w":190,"h":88,"titulo":"Acceso a red","subtitulo":"Ethernet, Wi-Fi, MAC","descripcion":"Absorbe las capas 1 y 2 de OSI: el medio físico y la entrega local — cables, ondas, MAC y switches."}],"enlaces":[{"de":"osi6","a":"app","discontinuo":true,"descripcion":"Sesión + presentación + aplicación de OSI viven juntas en la capa de aplicación de TCP/IP: los protocolos reales hacen los tres trabajos."},{"de":"osi4","a":"transporte","discontinuo":true,"descripcion":"Transporte ↔ transporte: la equivalencia perfecta. Mismo nombre, mismo trabajo: TCP y UDP."},{"de":"osi3","a":"internet","discontinuo":true,"descripcion":"Red (OSI) ↔ internet (TCP/IP): direcciones IP y routers. Dos nombres para la misma capa."},{"de":"osi2","a":"acceso","discontinuo":true,"descripcion":"Física + enlace de OSI se funden en el acceso a red de TCP/IP: señales, MAC y switches."}],"hint":"Toca una capa, una línea punteada o el título de cada columna."},"caption":"Las alturas cuentan la historia: aplicación de TCP/IP = OSI 5+6+7; acceso a red = OSI 1+2. Transporte e internet se corresponden una a una."}$j$),
  (3, 'quiz', $j${"variant":"multiple_choice","prompt":"Según el diagrama, ¿qué capas de OSI absorbe la capa de aplicación de TCP/IP?","options":["Solamente la capa 7","La capa 6 y la capa 7","La capa 5, la 6 y la 7","Absolutamente todas las capas"],"correctIndex":2,"feedback":{"correct":"Correcto. Por eso su caja es tres veces más alta: sesión + presentación + aplicación.","incorrect":"Mira las alturas: la caja de aplicación de TCP/IP cubre exactamente las capas 5, 6 y 7 de OSI."}}$j$),
  (4, 'quiz', $j${"variant":"multiple_choice","prompt":"¿Cuáles son las DOS capas que se corresponden una a una entre OSI y TCP/IP?","options":["La capa física y la capa de aplicación","La de sesión y la de presentación","La de enlace y la de acceso a red","Transporte (capa 4) y red/internet (capa 3)"],"correctIndex":3,"feedback":{"correct":"Correcto. Transporte ↔ transporte y red ↔ internet: equivalencias exactas. Las otras capas se agrupan.","incorrect":"Las equivalencias uno a uno son transporte ↔ transporte y red ↔ internet; las demás capas de OSI se funden en grupos."}}$j$),
  (5, 'resumen', $j${"title":"Resumen — El mapa completo","points":["OSI (7 capas) y TCP/IP (4 capas) describen lo mismo con distinto detalle.","Aplicación TCP/IP = OSI 5+6+7 · Acceso a red = OSI 1+2.","Transporte ↔ transporte y red ↔ internet: las dos equivalencias exactas.","OSI es el mapa (vocabulario); TCP/IP es el territorio (lo que se ejecuta).","Este diagrama vuelve en los cursos de nube y DFIR: guárdalo en la cabeza."]}$j$)
) as v(ord, kind, payload)
where c.slug = 'redes-y-sistemas' and l.slug = 'm02-l05-osi-vs-tcpip';

-- ═════════════════════════════════════════════════════════════════════
-- L06 · Encapsulamiento: el viaje del dato
-- ═════════════════════════════════════════════════════════════════════
insert into public.content_blocks (lesson_id, sort_order, kind, payload)
select l.id, v.ord, v.kind, v.payload::jsonb
from public.lessons l
join public.modules m on m.id = l.module_id
join public.courses c on c.id = m.course_id,
(values
  (1, 'texto', $j${"title":"Sobres dentro de sobres","body":"Sigamos una cita médica desde que la recepcionista pulsa Guardar hasta que sale por el cable. La app produce los DATOS. La capa de transporte los parte en trozos y a cada uno le añade su cabecera (con los puertos): ahora son SEGMENTOS. La capa de red envuelve cada segmento con otra cabecera (las direcciones IP de origen y destino): ahora son PAQUETES. La capa de enlace añade la suya (las MAC): ahora son TRAMAS. Y la capa física convierte todo en BITS — señales en el medio. Eso es ENCAPSULAR: cada capa mete lo de arriba en su propio sobre y le escribe SU información de entrega. Como la carta de la clínica: informe → sobre con dirección → paquete de mensajería → camión."}$j$),
  (2, 'texto', $j${"title":"El viaje de vuelta y quién abre qué","body":"En el destino ocurre lo inverso — DESENCAPSULAR: capa por capa se retira cada sobre hasta entregar los datos a la aplicación. Y aquí está la idea más útil de toda la lección: cada equipo del camino solo abre HASTA SU CAPA. El switch lee la trama (MAC, capa 2) y no mira más adentro. El router abre hasta el paquete (IP, capa 3) para decidir la ruta — y jamás necesita leer tu conversación. Solo el destino final desenvuelve todo. Esto explica algo enorme: tu tráfico cruza equipos de desconocidos todo el tiempo, y por eso el cifrado de las capas superiores importa tanto — los intermediarios ven los sobres, no la carta. Guarda esa imagen: es semilla directa de los cursos de seguridad y forense."}$j$),
  (3, 'quiz', $j${"variant":"multiple_choice","prompt":"Ordena los nombres que va tomando el dato al bajar por las capas:","options":["Datos → segmento → paquete → trama → bits","Datos → paquete → segmento → trama → bits","Bits → trama → paquete → segmento → datos","Datos → trama → paquete → segmento → bits"],"correctIndex":0,"feedback":{"correct":"Correcto. Transporte lo hace segmento, red lo hace paquete, enlace lo hace trama, física lo hace bits.","incorrect":"El orden de bajada: datos → SEGMENTO (transporte) → PAQUETE (red) → TRAMA (enlace) → BITS (física)."}}$j$),
  (4, 'quiz', $j${"variant":"multiple_choice","prompt":"¿Qué añade exactamente cada capa al encapsular?","options":["Una capa adicional de cifrado sobre los datos","Su propia cabecera, con datos de entrega de esa capa","Una copia de seguridad del contenido","Etiquetas de publicidad del fabricante"],"correctIndex":1,"feedback":{"correct":"Correcto. Puertos en el segmento, IPs en el paquete, MACs en la trama: cada sobre lleva su propia dirección.","incorrect":"Cada capa añade SU cabecera: el transporte pone puertos, la red pone IPs, el enlace pone MACs."}}$j$),
  (5, 'quiz', $j${"variant":"multiple_choice","prompt":"Un router de internet procesa tu tráfico hacia la clínica. ¿Hasta dónde 'abre' los sobres?","options":["Hasta los datos: lee toda la conversación entera","Hasta la trama (capa 2) y nada más profundo","Hasta el paquete (capa 3): le basta la IP de destino","No abre nada: solo repite las señales tal cual"],"correctIndex":2,"feedback":{"correct":"Exacto. El router es de capa 3: mira IPs y rutea. El contenido de tu conversación no es asunto suyo — y el cifrado se asegura de eso.","incorrect":"El router abre hasta SU capa: la 3. Lee la IP de destino, decide la ruta, y lo demás sigue cerrado dentro del paquete."}}$j$),
  (6, 'resumen', $j${"title":"Resumen — Encapsulamiento","points":["Encapsular: cada capa mete lo de arriba en su sobre y añade su cabecera con SU información de entrega.","Los nombres de bajada: datos → segmento (puertos) → paquete (IPs) → trama (MACs) → bits.","En el destino se desencapsula en orden inverso hasta entregar los datos a la app.","Cada equipo abre solo hasta su capa: switch → trama (2), router → paquete (3). Solo el destino abre todo.","Los intermediarios ven los sobres, no la carta: por eso el cifrado de capas superiores protege tu contenido en redes ajenas."]}$j$)
) as v(ord, kind, payload)
where c.slug = 'redes-y-sistemas' and l.slug = 'm02-l06-encapsulamiento';

-- ═════════════════════════════════════════════════════════════════════
-- X01 · Examen de región (jefe del módulo)
-- ═════════════════════════════════════════════════════════════════════
insert into public.content_blocks (lesson_id, sort_order, kind, payload)
select l.id, v.ord, v.kind, v.payload::jsonb
from public.lessons l
join public.modules m on m.id = l.module_id
join public.courses c on c.id = m.course_id,
(values
  (1, 'texto', $j${"title":"La segunda región","body":"Byte cruzó a la región de los modelos: diez preguntas guardan el paso. Aquí se habla el idioma de la profesión — capas, OSI, TCP/IP, encapsulamiento. Todo lo viste: por qué dividir en capas, quién vive en cada una, cómo se mapean los dos modelos y el viaje del dato sobre por sobre. Las preguntas que falles volverán al final hasta que las domines. Adelante."}$j$),
  (2, 'quiz', $j${"variant":"multiple_choice","prompt":"La razón de fondo para dividir la comunicación en capas es:","options":["Hacer las redes más lentas pero más seguras","Cumplir una norma legal obligatoria del sector","Vender más equipos de red a las empresas","Repartir trabajos con interfaces claras entre vecinas"],"correctIndex":3,"feedback":{"correct":"Correcto. Dividir y especializar: la razón por la que puedes cambiar el Wi-Fi por cable sin tocar tus apps.","incorrect":"Es la división del trabajo: cada capa un trabajo, interfaces claras, independencia entre niveles."}}$j$),
  (3, 'quiz', $j${"variant":"multiple_choice","prompt":"Cambias el medio físico (Wi-Fi → cable) y nada más cambia en tu equipo. Esto demuestra:","options":["La independencia: las de arriba no dependen del medio","Que el Wi-Fi que tenías era en realidad defectuoso","Que las aplicaciones no usan la red para nada","Que el cable no necesita instalar controladores"],"correctIndex":0,"feedback":{"correct":"Correcto. Cambiaste la capa 1 y las superiores ni se enteraron.","incorrect":"Es la independencia entre capas: el medio (capa 1) cambió y las capas superiores siguieron intactas."}}$j$),
  (4, 'quiz', $j${"variant":"multiple_choice","prompt":"El switch de la clínica y el router de salida trabajan, respectivamente, en las capas:","options":["Las capas 1 y 2, las dos de más bajo nivel","2 (MAC, dentro de la red) y 3 (IP, entre redes)","Las capas 3 y 4, de red y transporte","Las capas 2 y 7, enlace y aplicación"],"correctIndex":1,"feedback":{"correct":"Correcto. Switch = capa 2 con MACs; router = capa 3 con IPs.","incorrect":"El switch entrega tramas por MAC (capa 2); el router rutea paquetes por IP (capa 3)."}}$j$),
  (5, 'quiz', $j${"variant":"multiple_choice","prompt":"Muchos programas de tu laptop comparten UNA IP sin mezclar sus datos gracias a la capa de:","options":["La capa de red, que asigna la IP","La capa de enlace, que arma las tramas","Transporte, que lleva los datos de programa a programa","La capa de presentación, que da formato a los datos"],"correctIndex":2,"feedback":{"correct":"Correcto. La IP identifica la máquina; el transporte (capa 4) reparte entre los programas.","incorrect":"Es el transporte (capa 4): de programa a programa, extremo a extremo, aunque compartan IP."}}$j$),
  (6, 'quiz', $j${"variant":"multiple_choice","prompt":"'La capa de aplicación es el navegador.' ¿Verdadero?","options":["Sí: Chrome es exactamente la capa 7","Sí, pero únicamente cuando el navegador corre en Windows","Depende del navegador que se utilice","No: la capa 7 son los protocolos (HTTP, DNS), no las apps"],"correctIndex":3,"feedback":{"correct":"Correcto. La app habla capa 7; no ES la capa 7.","incorrect":"Clásico malentendido: la capa de aplicación son los protocolos (HTTP, DNS, SMTP) — el idioma, no el programa."}}$j$),
  (7, 'quiz', $j${"variant":"multiple_choice","prompt":"El modelo TCP/IP:","options":["Tiene 4 capas y nació de la implementación real de internet","Tiene 7 capas y fue creado por la ISO","Es un modelo puramente teórico que nunca llegó a usarse","Reemplazó a OSI también en el vocabulario diario"],"correctIndex":0,"feedback":{"correct":"Correcto. 4 capas nacidas de ARPANET: primero funcionó, después se documentó.","incorrect":"TCP/IP: 4 capas, nacido de la práctica (ARPANET). OSI es el teórico de 7 que ganó el vocabulario."}}$j$),
  (8, 'quiz', $j${"variant":"multiple_choice","prompt":"El mapeo correcto entre modelos es:","options":["La capa de aplicación de TCP/IP = solo la 7 de OSI","Aplicación=5+6+7 · transporte=4 · internet=3 · acceso=1+2","Acceso a red equivale a las capas 1, 2 y 3 de OSI","Internet de TCP/IP equivale a la capa 4 de OSI"],"correctIndex":1,"feedback":{"correct":"Correcto. Dos fusiones (arriba y abajo) y dos equivalencias exactas en el medio.","incorrect":"Aplicación absorbe 5+6+7; acceso a red absorbe 1+2; transporte ↔ 4 e internet ↔ 3 son exactas."}}$j$),
  (9, 'quiz', $j${"variant":"multiple_choice","prompt":"Al encapsular, los nombres del dato en orden de bajada son:","options":["Datos → trama → segmento → paquete → bits","Datos → paquete → trama → segmento → bits","Datos → segmento → paquete → trama → bits","Bits → paquete → segmento → trama → datos"],"correctIndex":2,"feedback":{"correct":"Correcto. Segmento (puertos), paquete (IPs), trama (MACs), bits (señales).","incorrect":"De arriba hacia abajo: datos → segmento → paquete → trama → bits. Cada capa añade su sobre."}}$j$),
  (10, 'quiz', $j${"variant":"multiple_choice","prompt":"Tu paquete cruza doce routers ajenos hasta llegar a la clínica. ¿Por qué ninguno lee tu conversación?","options":["Porque leer el tráfico ajeno es ilegal y con eso basta","Porque los routers no tienen memoria para guardarlo","Porque tu conversación viaja por un cable distinto","Cada equipo abre solo hasta su capa; el router llega a la 3"],"correctIndex":3,"feedback":{"correct":"Correcto. El router mira IPs y rutea; el contenido queda en sobres interiores que además viajan cifrados.","incorrect":"Cada equipo abre hasta su capa: al router le basta la IP (capa 3). El contenido queda dentro — y el cifrado lo protege."}}$j$),
  (11, 'quiz', $j${"variant":"multiple_choice","prompt":"Pregunta final de entrevista: '¿Para qué estudiar OSI si internet corre sobre TCP/IP?' Tu respuesta senior:","options":["OSI es el vocabulario y el marco de diagnóstico; TCP/IP ejecuta","OSI es obsoleto y no vale la pena estudiarlo","Porque OSI es una tecnología más moderna y rápida que TCP/IP","Para aprobar el examen y olvidarlo después"],"correctIndex":0,"feedback":{"correct":"Impecable. El mapa y el territorio: OSI para pensar, hablar y diagnosticar; TCP/IP para ejecutar.","incorrect":"La respuesta senior: OSI es el idioma común ('capa 3', 'capa 7') y el marco para aislar problemas; TCP/IP es la pila real. Conviven."}}$j$)
) as v(ord, kind, payload)
where c.slug = 'redes-y-sistemas' and l.slug = 'm02-x01-examen';
